/**
 * useEdgeTTS — Microsoft Edge Neural TTS via the API server.
 *
 * Produces natural Indian-accented speech for 13 languages with real
 * male / female neural voices. Same interface as useSpeechSynthesis so
 * pages can swap with minimal changes.
 *
 * GLOBAL SINGLETON: All hook instances share a single Audio element so
 * English Guru and Interview Ace (or any two tools) can never speak
 * simultaneously — calling speak() anywhere immediately stops whatever
 * else is playing.
 */
import { useState, useEffect, useRef, useCallback } from "react";

export type VoiceGender = "male" | "female" | "auto";

export type EdgeSpeakOptions = {
  voiceGender?: VoiceGender;
  /** playbackRate multiplier — default 1.0 (Edge voices are already natural speed) */
  rate?: number;
  /** ignored for Edge TTS (pitch is set by the neural model, not adjustable) */
  pitch?: number;
  /**
   * Tutor voice style key (e.g. "priya", "arjun", "rahul"). When supplied, the
   * API server maps this to a specific Edge Neural voice so each tutor has a
   * distinct accent. Falls back to gender-based selection when absent.
   */
  voiceStyle?: string;
};

const BASE = (import.meta.env.BASE_URL ?? "/").replace(/\/$/, "");

// ---------------------------------------------------------------------------
// Audio context unlock
//
// Chrome's autoplay policy blocks audio.play() unless called from within a
// user-gesture event stack. Because TTS fetches take 1-4 seconds (AI + Edge
// network), the gesture context has expired long before play() is attempted.
//
// The fix: call unlockAudio() SYNCHRONOUSLY inside the click handler that
// starts live chat or an interview. This plays a silent MP3 from within the
// gesture, which permanently unlocks the tab's audio context for the lifetime
// of the session. All subsequent audio.play() calls (even async ones) then
// succeed without a NotAllowedError.
// ---------------------------------------------------------------------------
let _unlocked = false;

/**
 * unlockAudio — must be called synchronously from a user-gesture handler
 * (onClick, onKeyDown, etc.) before any async operations.  Safe to call
 * multiple times; subsequent calls are no-ops.
 */
export function unlockAudio(): void {
  if (_unlocked) return;
  // Optimistic: mark unlocked so concurrent callers don't race.
  // Reset to false only if play() actually rejects so retries work.
  _unlocked = true;
  try {
    const SILENT_MP3 =
      "data:audio/mpeg;base64,";
    const sil = new Audio(SILENT_MP3);
    sil.volume = 0;
    sil.play().catch(() => {
      _unlocked = false; // blocked — allow retry on next user gesture
    });
  } catch {
    _unlocked = false;
  }
}

// ---------------------------------------------------------------------------
// Module-level singleton — exactly one audio element and one AbortController
// across the entire app lifetime. Guarantees only one AI voice at a time.
// ---------------------------------------------------------------------------
let _audio: HTMLAudioElement | null = null;
let _abort: AbortController | null = null;
let _url:   string | null = null;
// Hook instances register here to be notified when global stop happens
// so they can reset their own isSpeaking state.
const _stopListeners = new Set<() => void>();

function globalStop() {
  _abort?.abort();
  _abort = null;
  if (_audio) {
    _audio.pause();
    _audio.onended = null;
    _audio.onerror = null;
    _audio.src    = "";
    _audio        = null;
  }
  if (_url) { URL.revokeObjectURL(_url); _url = null; }
  // Notify all mounted hook instances so isSpeaking resets everywhere
  _stopListeners.forEach(fn => fn());
}

// ---------------------------------------------------------------------------

export function useEdgeTTS() {
  const [isSpeaking, setIsSpeaking] = useState(false);
  // Track whether THIS instance is the active speaker so only it fires onEnd
  const ownerRef = useRef(false);

  // Register / deregister global-stop listener on mount / unmount
  useEffect(() => {
    const onGlobalStop = () => {
      if (ownerRef.current) {
        ownerRef.current = false;
        setIsSpeaking(false);
      }
    };
    _stopListeners.add(onGlobalStop);
    return () => {
      _stopListeners.delete(onGlobalStop);
      // If this instance was speaking when unmounted, relinquish ownership FIRST
      // so no post-unmount setIsSpeaking fires, then stop global audio.
      if (ownerRef.current) {
        ownerRef.current = false;
        globalStop();
      }
    };
  }, []);

  const stop = useCallback(() => {
    globalStop();
  }, []);

  const speak = useCallback(
    async (
      text: string,
      language = "English",
      onEnd?: () => void,
      options: EdgeSpeakOptions = {},
    ) => {
      if (!text.trim()) { onEnd?.(); return; }

      // Stop any currently-playing audio globally (resets all hook isSpeaking states)
      globalStop();

      ownerRef.current = true;
      setIsSpeaking(true);

      const gender: "male" | "female" =
        options.voiceGender === "male" ? "male" : "female";

      const ctrl = new AbortController();
      _abort = ctrl;

      // Auto-abort if the TTS fetch hangs (slow network, server stall).
      // 15 s is generous; real responses are usually < 2 s.
      const hangTimer = setTimeout(() => { if (_abort === ctrl) ctrl.abort(); }, 15_000);

      try {
        const res = await fetch(`${BASE}/api/tts`, {
          method:  "POST",
          headers: { "Content-Type": "application/json" },
          credentials: "include",
          body:    JSON.stringify({ text: text.trim(), language, gender, voiceStyle: options.voiceStyle }),
          signal:  ctrl.signal,
        });
        clearTimeout(hangTimer);

        if (!res.ok || ctrl.signal.aborted) {
          if (ownerRef.current) { ownerRef.current = false; setIsSpeaking(false); }
          onEnd?.();
          return;
        }

        const blob = await res.blob();
        if (ctrl.signal.aborted) {
          if (ownerRef.current) { ownerRef.current = false; setIsSpeaking(false); }
          onEnd?.();
          return;
        }

        const url = URL.createObjectURL(blob);
        _url = url;

        const audio = new Audio(url);
        _audio = audio;

        const rate = options.rate;
        if (rate && rate !== 1.0) audio.playbackRate = Math.max(0.8, Math.min(rate, 2.0));

        const cleanup = () => {
          // Only the owner fires onEnd — prevents double-fire if globally stopped
          if (ownerRef.current) {
            ownerRef.current = false;
            setIsSpeaking(false);
            onEnd?.();
          }
          URL.revokeObjectURL(url);
          if (_url === url)   _url   = null;
          if (_audio === audio) _audio = null;
        };

        audio.onended = cleanup;
        audio.onerror = cleanup;

        try {
          await audio.play();
        } catch {
          cleanup();
        }
      } catch (err: unknown) {
        clearTimeout(hangTimer);
        // Fire onEnd whenever we are still the active owner.
        // • Timeout-triggered abort: ownerRef is still true → fire onEnd ✓
        // • New speak() evicted us (globalStop → ownerRef=false): skip onEnd ✓
        // • Any other error: ownerRef is still true → fire onEnd ✓
        if (ownerRef.current) { ownerRef.current = false; setIsSpeaking(false); onEnd?.(); }
      }
    },
    [],
  );

  return {
    isSpeaking,
    isSupported: true as const,
    speak,
    stop,
  };
}
